import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'app_colors.dart';import 'app_spacing.dart';import 'app_typography.dart';class DsFab extends StatefulWidget {  final IconData icon;  final VoidCallback onPressed;  const DsFab({    super.key,    required this.icon,    required this.onPressed,  });  @override  State<DsFab> createState() => _DsFabState();}@overrideclass _DsFabState extends State<DsFab> with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<double> _scaleAnimation;  late Animation<double> _glowAnimation;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 200),      reverseDuration: const Duration(milliseconds: 100),    );    _scaleAnimation = Tween<double>(begin: 1.0, end: 0.9).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );    _glowAnimation = Tween<double>(begin: 0.0, end: 1.0).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _onTapDown(TapDownDetails details) {    HapticFeedback.lightImpact();    _controller.forward();  }  void _onTapUp(TapUpDetails details) {    _controller.reverse();  }  void _onTapCancel() {    _controller.reverse();  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTapDown: _onTapDown,      onTapUp: _onTapUp,      onTapCancel: _onTapCancel,      onTap: widget.onPressed,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Transform.scale(            scale: _scaleAnimation.value,            child: Container(              width: AppSpacing.fabSize,              height: AppSpacing.fabSize,              decoration: BoxDecoration(                color: AppColors.primary,                shape: BoxShape.circle,                boxShadow: [                  BoxShadow(                    color: Colors.black.withOpacity(0.4),                    offset: const Offset(0, 8),                    blurRadius: 16,                  ),                  BoxShadow(                    color: Colors.black.withOpacity(0.2),                    offset: const Offset(0, 2),                    blurRadius: 6,                  ),                  if (_glowAnimation.value > 0)                    BoxShadow(                      color: AppColors.primary.withOpacity(0.5 * _glowAnimation.value),                      blurRadius: 15 * _glowAnimation.value,                      spreadRadius: 3 * _glowAnimation.value,                    ),                ],              ),              child: Icon(                widget.icon,                color: AppColors.buttonTextPrimary,                size: AppTypography.h2.fontSize,              ),            ),          );        },      ),    );  }}